func TestCredentialSource_Get_AWSChain(t *testing.T) {
	logger := zaptest.NewLogger(t)
	cfgs := config.CredentialsConfig{
		"aws": &config.CredentialConfig{
			Type: config.CredentialTypeAWSChain,
			AWSChain: &config.AWSChainConfig{
				Region: "us-east-1",
			},
		},
	}

	cs := New(logger, cfgs)

	t.Run("get aws chain credential", func(t *testing.T) {
		cred, err := cs.Get("aws")
		// Expect an error because no actual AWS credentials are available in the test environment
		if err == nil {
			// If AWS credentials are available (e.g., in EC2 or with AWS env vars),
			// the credential should be returned successfully
			assert.NotNil(t, cred)
			assert.Equal(t, config.CredentialTypeAWSChain, cred.Type())
		}
